1	import { quote, claim } from "./claim-office.js";
2	
3	const KNOWN_ITEM_TYPES = new Set([
4	  "sword",
5	  "amulet",
6	  "staff",
7	  "potion",
8	  "rune",
9	  "moonstone",
10	]);
11	
12	function assertKnownItemTypes(items: { type: string }[]): void {
13	  for (const item of items) {
14	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
15	      throw new Error(`Unknown item type: ${item.type}`);
16	    }
17	  }
18	}
19	
20	function assertDamagesCoveredByPolicy(
21	  policyItems: { type: string }[],
22	  damages: { itemType: string }[],
23	): void {
24	  const policyItemTypes = policyItems.map((item) => item.type);
25	  for (const damage of damages) {
26	    if (!policyItemTypes.includes(damage.itemType)) {
27	      throw new Error(
28	        `Claim damages an item not in policy: ${damage.itemType}`,
29	      );
30	    }
31	  }
32	}
33	
34	export function runScenario(scenario: any): { results: unknown[] } {
35	  const results: unknown[] = [];
36	  let quoteCount = 0;
37	  const remainingCaps = new Map<number, number>();
38	  for (const step of scenario.steps) {
39	    if (step.op === "quote") {
40	      assertKnownItemTypes(step.items);
41	      const premium = quote({
42	        customer: {
43	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
44	          previousContracts: quoteCount,
45	        },
46	        items: step.items,
47	      });
48	      results.push({ premium });
49	      quoteCount++;
50	    } else if (step.op === "claim") {
51	      const policyStep = scenario.steps[step.policy];
52	      assertDamagesCoveredByPolicy(policyStep.items, step.incident.damages);
53	      const { payout, remainingCap } = claim({
54	        items: policyStep.items,
55	        incident: step.incident,
56	        remainingCap: remainingCaps.get(step.policy),
57	      });
58	      remainingCaps.set(step.policy, remainingCap);
59	      results.push({ payout, remainingCap });
60	    }
61	  }
62	  return { results };
63	}
